import React, { useState, useEffect, useMemo } from 'react';
import { api } from '../api';
import { City } from '../App';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell,
  LineChart,
  Line,
  AreaChart,
  Area
} from 'recharts';
import { 
  Filter, 
  Download, 
  Calendar, 
  MapPin, 
  User, 
  TrendingUp, 
  Wallet, 
  ShoppingBag,
  DollarSign,
  Users,
  ArrowUpDown,
  Clock,
  Award,
  Target,
  Eye,
  Calculator,
  FileText,
  Building
} from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';

interface StatsPageProps {
  isAdmin: boolean;
}

type StatView = 'overview' | 'profit' | 'salary' | 'comparison' | 'performance';
type TimeRange = 'day' | 'week' | 'month' | 'quarter' | 'year' | 'custom';
type ComparisonType = 'points' | 'cities' | 'workers' | 'periods';

export default function StatsPage({ isAdmin }: StatsPageProps) {
  const [reports, setReports] = useState<any[]>([]);
  const [salaryPayments, setSalaryPayments] = useState<any[]>([]);
  const [points, setPoints] = useState<any[]>([]);
  const [workers, setWorkers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeView, setActiveView] = useState<StatView>('overview');
  
  // Filters
  const [filterCity, setFilterCity] = useState<string>('all');
  const [filterPoint, setFilterPoint] = useState<string>('all');
  const [filterWorker, setFilterWorker] = useState<string>('all');
  const [dateStart, setDateStart] = useState<string>('');
  const [dateEnd, setDateEnd] = useState<string>('');
  const [timeRange, setTimeRange] = useState<TimeRange>('month');
  
  // Comparison
  const [comparisonType, setComparisonType] = useState<ComparisonType>('points');
  const [compareItems, setCompareItems] = useState<string[]>([]);

  useEffect(() => {
    if (isAdmin) {
      setLoading(true);
      
      // Временно загружаем данные без строгой проверки ошибок
      const loadData = async () => {
        try {
          const [reportsData, salaryData, chPoints, ozPoints, chWorkers, ozWorkers] = await Promise.all([
            fetch('/api/admin/reports').then(r => r.ok ? r.json() : []),
            fetch('/api/admin/salary-payments').then(r => r.ok ? r.json() : []),
            fetch('/api/points/chelyabinsk').then(r => r.ok ? r.json() : []),
            fetch('/api/points/ozersk').then(r => r.ok ? r.json() : []),
            fetch('/api/workers/chelyabinsk').then(r => r.ok ? r.json() : []),
            fetch('/api/workers/ozersk').then(r => r.ok ? r.json() : [])
          ]);
          
          setReports(reportsData.filter((r: any) => r.status === 'confirmed'));
          setSalaryPayments(salaryData || []);
          setPoints([...(chPoints || []), ...(ozPoints || [])]);
          setWorkers([...(chWorkers || []), ...(ozWorkers || [])]);
          setLoading(false);
        } catch (error) {
          console.error('Error loading stats data:', error);
          // Если API не работает, используем пустые данные
          setReports([]);
          setSalaryPayments([]);
          setPoints([]);
          setWorkers([]);
          setLoading(false);
        }
      };
      
      loadData();
    }
  }, [isAdmin]);

  // Set default date range based on timeRange
  useEffect(() => {
    const today = new Date();
    let start = new Date();
    
    switch (timeRange) {
      case 'day':
        start.setDate(today.getDate() - 1);
        break;
      case 'week':
        start.setDate(today.getDate() - 7);
        break;
      case 'month':
        start.setMonth(today.getMonth() - 1);
        break;
      case 'quarter':
        start.setMonth(today.getMonth() - 3);
        break;
      case 'year':
        start.setFullYear(today.getFullYear() - 1);
        break;
    }
    
    setDateStart(start.toISOString().split('T')[0]);
    setDateEnd(today.toISOString().split('T')[0]);
  }, [timeRange]);

  const filteredReports = useMemo(() => {
    return reports.filter(r => {
      const cityMatch = filterCity === 'all' || r.city === filterCity;
      const pointMatch = filterPoint === 'all' || r.point_id.toString() === filterPoint;
      const workerMatch = filterWorker === 'all' || r.worker_id === filterWorker;
      const startMatch = !dateStart || r.date >= dateStart;
      const endMatch = !dateEnd || r.date <= dateEnd;
      return cityMatch && pointMatch && workerMatch && startMatch && endMatch;
    });
  }, [reports, filterCity, filterPoint, filterWorker, dateStart, dateEnd]);

  const filteredSalaryPayments = useMemo(() => {
    return salaryPayments.filter(p => {
      const cityMatch = filterCity === 'all' || p.city === filterCity;
      const workerMatch = filterWorker === 'all' || p.worker_id === filterWorker;
      const startMatch = !dateStart || p.date >= dateStart;
      const endMatch = !dateEnd || p.date <= dateEnd;
      return cityMatch && workerMatch && startMatch && endMatch;
    });
  }, [salaryPayments, filterCity, filterWorker, dateStart, dateEnd]);

  // Calculate comprehensive statistics
  const stats = useMemo(() => {
    try {
      const totalCash = filteredReports.reduce((sum, r) => sum + (r.cash || 0), 0);
      const totalPurchase = filteredReports.reduce((sum, r) => sum + (r.purchase || 0), 0);
      const totalHours = filteredReports.reduce((sum, r) => sum + (r.hours || 0), 0);
      const totalSalary = filteredSalaryPayments.reduce((sum, p) => sum + (p.amount || 0), 0);
      const profit = totalCash - totalPurchase - totalSalary;
      
      // Group by date for charts
      const dailyData = filteredReports.reduce((acc: any, r) => {
        if (!acc[r.date]) acc[r.date] = { date: r.date, cash: 0, purchase: 0, hours: 0, profit: 0 };
        acc[r.date].cash += r.cash || 0;
        acc[r.date].purchase += r.purchase || 0;
        acc[r.date].hours += r.hours || 0;
        acc[r.date].profit += (r.cash || 0) - (r.purchase || 0);
        return acc;
      }, {});
      
      const lineChartData = Object.values(dailyData).sort((a: any, b: any) => a.date.localeCompare(b.date));
      
      // Group by point
      const pointData = filteredReports.reduce((acc: any, r) => {
        if (!acc[r.point_name]) acc[r.point_name] = { name: r.point_name, cash: 0, purchase: 0, profit: 0, hours: 0 };
        acc[r.point_name].cash += r.cash || 0;
        acc[r.point_name].purchase += r.purchase || 0;
        acc[r.point_name].profit += (r.cash || 0) - (r.purchase || 0);
        acc[r.point_name].hours += r.hours || 0;
        return acc;
      }, {});
      
      const pieChartData = Object.values(pointData);
      
      // Worker performance
      const workerData = filteredReports.reduce((acc: any, r) => {
        // Используем ID отчета как уникальный ключ, но группируем по сотрудникам
        const workerKey = `${r.worker_id}_${r.worker_name}_${r.city}`;
        if (!acc[workerKey]) acc[workerKey] = { 
          name: r.worker_name, 
          workerId: r.worker_id,
          city: r.city,
          cash: 0, 
          hours: 0, 
          reports: 0, 
          avgCash: 0,
          firstDate: r.date,
          lastDate: r.date,
          reportIds: [] // Добавляем массив ID отчетов для отслеживания
        };
        acc[workerKey].cash += r.cash || 0;
        acc[workerKey].hours += r.hours || 0;
        acc[workerKey].reports += 1;
        acc[workerKey].reportIds.push(r.id); // Сохраняем ID отчета
        acc[workerKey].firstDate = acc[workerKey].firstDate < r.date ? acc[workerKey].firstDate : r.date;
        acc[workerKey].lastDate = acc[workerKey].lastDate > r.date ? acc[workerKey].lastDate : r.date;
        return acc;
      }, {});
      
      Object.values(workerData).forEach((w: any) => {
        w.avgCash = w.cash / w.reports;
        w.efficiency = w.hours > 0 ? w.cash / w.hours : 0;
        // Добавляем информацию о периоде работы
        w.workPeriod = `${new Date(w.firstDate).toLocaleDateString('ru-RU')} - ${new Date(w.lastDate).toLocaleDateString('ru-RU')}`;
      });
      
      return { 
        totalCash, 
        totalPurchase, 
        totalHours, 
        totalSalary,
        profit,
        lineChartData, 
        pieChartData,
        workerData: Object.values(workerData),
        pointData: Object.values(pointData)
      };
    } catch (error) {
      console.error('Error calculating stats:', error);
      // Возвращаем пустые данные в случае ошибки
      return {
        totalCash: 0,
        totalPurchase: 0,
        totalHours: 0,
        totalSalary: 0,
        profit: 0,
        lineChartData: [],
        pieChartData: [],
        workerData: [],
        pointData: []
      };
    }
  }, [filteredReports, filteredSalaryPayments]);

  // Comparison data
  const comparisonData = useMemo(() => {
    switch (comparisonType) {
      case 'points':
        return stats.pointData.map(p => ({
          name: p.name,
          cash: p.cash,
          profit: p.profit,
          hours: p.hours,
          efficiency: p.cash / p.hours || 0
        }));
      case 'cities':
        const cityData = filteredReports.reduce((acc: any, r) => {
          if (!acc[r.city]) acc[r.city] = { name: r.city === 'chelyabinsk' ? 'Челябинск' : 'Озерск', cash: 0, profit: 0, hours: 0 };
          acc[r.city].cash += r.cash;
          acc[r.city].profit += r.cash - r.purchase;
          acc[r.city].hours += r.hours;
          return acc;
        }, {});
        return Object.values(cityData);
      case 'workers':
        return stats.workerData.slice(0, 10).map(w => ({
          name: `${w.name} (ID: ${w.workerId})`,
          cash: w.cash,
          profit: w.cash, // Для сотрудников profit = cash
          hours: w.hours,
          efficiency: w.efficiency || 0,
          city: w.city,
          workPeriod: w.workPeriod,
          uniqueKey: `worker-comp-${w.workerId}-${w.name.replace(/\s+/g, '-')}` // Добавляем уникальный ключ
        }));
      case 'periods':
        // Group by weeks or months
        const periodData = filteredReports.reduce((acc: any, r) => {
          const period = timeRange === 'week' 
            ? `Неделя ${Math.ceil(new Date(r.date).getDate() / 7)}`
            : new Date(r.date).toLocaleDateString('ru-RU', { month: 'short' });
          if (!acc[period]) acc[period] = { name: period, cash: 0, profit: 0, hours: 0 };
          acc[period].cash += r.cash;
          acc[period].profit += r.cash - r.purchase;
          acc[period].hours += r.hours;
          return acc;
        }, {});
        return Object.values(periodData);
      default:
        return [];
    }
  }, [comparisonType, filteredReports, stats.pointData, stats.workerData, timeRange]);

  const COLORS = ['#059669', '#2563eb', '#d97706', '#dc2626', '#7c3aed', '#db2777', '#0891b2', '#ea580c'];

  if (!isAdmin) return <div className="p-8 text-center font-bold text-red-500">Доступ запрещен</div>;

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="text-center">
          <div className="w-12 h-12 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-stone-500 font-medium">Загрузка статистики...</p>
        </div>
      </div>
    );
  }

  if (reports.length === 0 && salaryPayments.length === 0) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <div className="text-center">
          <div className="w-16 h-16 bg-stone-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <TrendingUp className="w-8 h-8 text-stone-400" />
          </div>
          <p className="text-stone-500 font-bold text-lg mb-2">Нет данных для отображения</p>
          <p className="text-stone-400 text-sm">Сначала добавьте отчеты для получения статистики</p>
        </div>
      </div>
    );
  }

  const renderOverview = () => (
    <div className="space-y-6">
      {/* Summary Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
          <div className="bg-emerald-100 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
            <Wallet className="text-emerald-600 w-6 h-6" />
          </div>
          <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Общая касса</p>
          <p className="text-2xl lg:text-3xl font-black text-stone-900">{stats.totalCash.toLocaleString()} ₽</p>
        </div>
        <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
          <div className="bg-amber-100 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
            <ShoppingBag className="text-amber-600 w-6 h-6" />
          </div>
          <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Общий закуп</p>
          <p className="text-2xl lg:text-3xl font-black text-stone-900">{stats.totalPurchase.toLocaleString()} ₽</p>
        </div>
        <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
          <div className="bg-blue-100 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
            <DollarSign className="text-blue-600 w-6 h-6" />
          </div>
          <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Прибыль</p>
          <p className={`text-2xl lg:text-3xl font-black ${stats.profit >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
            {stats.profit.toLocaleString()} ₽
          </p>
        </div>
        <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
          <div className="bg-purple-100 w-12 h-12 rounded-2xl flex items-center justify-center mb-4">
            <Calculator className="text-purple-600 w-6 h-6" />
          </div>
          <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">Выплачено зарплат</p>
          <p className="text-2xl lg:text-3xl font-black text-stone-900">{stats.totalSalary.toLocaleString()} ₽</p>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
          <h3 className="font-bold text-sm uppercase tracking-widest text-stone-500 mb-6">Динамика прибыли</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={stats.lineChartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f1f1" />
                <XAxis 
                  dataKey="date" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fontWeight: 'bold', fill: '#a8a29e' }}
                  tickFormatter={(val) => new Date(val).toLocaleDateString('ru-RU', { day: 'numeric', month: 'short' })}
                />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold', fill: '#a8a29e' }} />
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                  labelStyle={{ fontWeight: 'bold', marginBottom: '4px' }}
                />
                <Area type="monotone" dataKey="profit" stroke="#059669" fill="#059669" fillOpacity={0.3} strokeWidth={2} />
                <Area type="monotone" dataKey="cash" stroke="#2563eb" fill="#2563eb" fillOpacity={0.2} strokeWidth={2} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
          <h3 className="font-bold text-sm uppercase tracking-widest text-stone-500 mb-6">Доля по точкам</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.pieChartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="cash"
                >
                  {stats.pieChartData.map((entry, index) => (
                    <Cell key={`cell-${entry.name}-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );

  const renderSalary = () => (
    <div className="space-y-6">
      <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
        <div className="flex justify-between items-center mb-6">
          <h3 className="font-bold text-lg uppercase tracking-wider text-stone-700">Выплаченные зарплаты</h3>
          <button className="bg-emerald-600 text-white px-4 py-2 rounded-xl font-bold text-sm flex items-center gap-2">
            <FileText className="w-4 h-4" />
            Добавить выплату
          </button>
        </div>
        
        <div className="space-y-3">
          {filteredSalaryPayments.map((payment, index) => (
            <div key={`payment-${payment.id}-${index}`} className="bg-stone-50 rounded-2xl p-4 border border-stone-200">
              <div className="flex justify-between items-start">
                <div>
                  <p className="font-bold text-stone-900">{payment.worker_name}</p>
                  <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">
                    {new Date(payment.date).toLocaleDateString('ru-RU')} • {payment.city === 'chelyabinsk' ? 'ЧБ' : 'ОЗ'}
                  </p>
                  {payment.comment && (
                    <p className="text-xs text-stone-600 mt-1 italic">"{payment.comment}"</p>
                  )}
                </div>
                <div className="text-right">
                  <p className="font-black text-emerald-600 text-lg">{payment.amount.toLocaleString()} ₽</p>
                  <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">ID: {payment.worker_id}</p>
                </div>
              </div>
            </div>
          ))}
          {filteredSalaryPayments.length === 0 && (
            <div className="text-center py-12 text-stone-400">
              <Calculator className="w-12 h-12 mx-auto mb-4 text-stone-300" />
              <p className="font-bold uppercase text-xs tracking-widest">Зарплатные выплаты не найдены</p>
            </div>
          )}
        </div>
      </div>

      {/* Salary Statistics */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
          <h3 className="font-bold text-sm uppercase tracking-widest text-stone-500 mb-6">Зарплаты по месяцам</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.lineChartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f1f1" />
                <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold', fill: '#a8a29e' }} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold', fill: '#a8a29e' }} />
                <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }} />
                <Bar dataKey="cash" fill="#8b5cf6" radius={[8, 8, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
          <h3 className="font-bold text-sm uppercase tracking-widest text-stone-500 mb-6">Топ сотрудников по зарплатам</h3>
          <div className="space-y-3">
            {stats.workerData
              .sort((a: any, b: any) => b.cash - a.cash)
              .slice(0, 5)
              .map((worker: any, index) => (
                <div key={`worker-stats-${worker.workerId}-${worker.name.replace(/\s+/g, '-')}`} className="flex items-center justify-between p-3 bg-stone-50 rounded-xl">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 bg-purple-100 rounded-full flex items-center justify-center text-purple-600 font-bold text-sm">
                      {index + 1}
                    </div>
                    <div>
                      <p className="font-bold text-stone-900">{worker.name}</p>
                      <p className="text-xs text-stone-500">ID: {worker.workerId} • {worker.city === 'chelyabinsk' ? 'ЧБ' : 'ОЗ'}</p>
                      <p className="text-xs text-stone-400">{worker.workPeriod}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-stone-900">{worker.cash.toLocaleString()} ₽</p>
                    <p className="text-xs text-stone-500">{worker.hours.toFixed(1)} ч • {worker.reports} смен</p>
                  </div>
                </div>
              ))}
          </div>
        </div>
      </div>
    </div>
  );

  const renderComparison = () => (
    <div className="space-y-6">
      <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
        <h3 className="font-bold text-lg uppercase tracking-wider text-stone-700 mb-6">Сравнение</h3>
        
        {/* Comparison Controls */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
          <div>
            <label className="text-[10px] font-bold text-stone-400 uppercase ml-1">Тип сравнения</label>
            <select 
              value={comparisonType}
              onChange={(e) => setComparisonType(e.target.value as ComparisonType)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-2.5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500"
            >
              <option value="points">Точки</option>
              <option value="cities">Города</option>
              <option value="workers">Сотрудники</option>
              <option value="periods">Периоды</option>
            </select>
          </div>
          <div>
            <label className="text-[10px] font-bold text-stone-400 uppercase ml-1">Период</label>
            <select 
              value={timeRange}
              onChange={(e) => setTimeRange(e.target.value as TimeRange)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-2.5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500"
            >
              <option value="day">День</option>
              <option value="week">Неделя</option>
              <option value="month">Месяц</option>
              <option value="quarter">Квартал</option>
              <option value="year">Год</option>
            </select>
          </div>
        </div>

        {/* Comparison Chart */}
        <div className="h-[400px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={comparisonData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f1f1" />
              <XAxis 
                dataKey="name" 
                axisLine={false} 
                tickLine={false} 
                tick={{ fontSize: 10, fontWeight: 'bold', fill: '#a8a29e' }}
                angle={-45}
                textAnchor="end"
                height={80}
              />
              <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 'bold', fill: '#a8a29e' }} />
              <Tooltip 
                contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
              />
              <Bar dataKey="cash" fill="#059669" radius={[8, 8, 0, 0]} name="Касса" />
              <Bar dataKey="profit" fill="#2563eb" radius={[8, 8, 0, 0]} name="Прибыль" />
              {comparisonType === 'workers' && (
                <Bar dataKey="efficiency" fill="#d97706" radius={[8, 8, 0, 0]} name="Эффективность" />
              )}
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Comparison Table */}
      <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm">
        <h3 className="font-bold text-sm uppercase tracking-widest text-stone-500 mb-6">Детальное сравнение</h3>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-stone-200">
                <th className="text-left p-3 font-bold text-[10px] uppercase tracking-wider text-stone-400">Название</th>
                <th className="text-right p-3 font-bold text-[10px] uppercase tracking-wider text-stone-400">Касса</th>
                <th className="text-right p-3 font-bold text-[10px] uppercase tracking-wider text-stone-400">Прибыль</th>
                <th className="text-right p-3 font-bold text-[10px] uppercase tracking-wider text-stone-400">Часы</th>
                {comparisonType === 'workers' && (
                <th className="text-right p-3 font-bold text-[10px] uppercase tracking-wider text-stone-400">Период работы</th>
              )}
              </tr>
            </thead>
            <tbody>
              {comparisonData
                .sort((a: any, b: any) => b.profit - a.profit)
                .map((item: any, index) => (
                  <tr key={item.uniqueKey || `${item.name}-${index}`} className="border-b border-stone-100 hover:bg-stone-50">
                    <td className="p-3">
                      <div className="flex items-center gap-2">
                        <div className="w-6 h-6 bg-emerald-100 rounded-full flex items-center justify-center text-emerald-600 font-bold text-xs">
                          {index + 1}
                        </div>
                        <span className="font-bold text-stone-900">{item.name}</span>
                      </div>
                    </td>
                    <td className="p-3 text-right font-black text-emerald-600">{item.cash.toLocaleString()} ₽</td>
                    <td className="p-3 text-right font-black text-blue-600">{item.profit.toLocaleString()} ₽</td>
                    <td className="p-3 text-right font-bold text-stone-900">{item.hours.toFixed(1)} ч</td>
                    <td className="p-3 text-right font-bold text-amber-600">{item.efficiency ? item.efficiency.toFixed(0) : 0} ₽/ч</td>
                    {comparisonType === 'workers' && (
                      <td className="p-3 text-right">
                        <div className="text-xs text-stone-600">
                          {item.workPeriod || '-'}
                        </div>
                      </td>
                    )}
                  </tr>
                ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-black tracking-tight uppercase">Статистика</h2>
        
        {/* View Selector */}
        <div className="flex bg-stone-100 border border-stone-200 rounded-xl p-1">
          <button 
            onClick={() => setActiveView('overview')}
            className={`px-3 py-2 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
              activeView === 'overview' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-500'
            }`}
          >
            <Eye className="w-3 h-3" /> Обзор
          </button>
          <button 
            onClick={() => setActiveView('salary')}
            className={`px-3 py-2 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
              activeView === 'salary' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-500'
            }`}
          >
            <Calculator className="w-3 h-3" /> Зарплаты
          </button>
          <button 
            onClick={() => setActiveView('comparison')}
            className={`px-3 py-2 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
              activeView === 'comparison' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-500'
            }`}
          >
            <ArrowUpDown className="w-3 h-3" /> Сравнение
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm space-y-4">
        <div className="flex items-center gap-2 mb-2">
          <Filter className="w-4 h-4 text-stone-400" />
          <h3 className="font-bold text-sm uppercase tracking-widest text-stone-500">Фильтры</h3>
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-stone-400 uppercase ml-1">Город</label>
            <select 
              value={filterCity}
              onChange={(e) => setFilterCity(e.target.value)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-2.5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500"
            >
              <option value="all">Все города</option>
              <option value="chelyabinsk">Челябинск</option>
              <option value="ozersk">Озерск</option>
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-bold text-stone-400 uppercase ml-1">Точка</label>
            <select 
              value={filterPoint}
              onChange={(e) => setFilterPoint(e.target.value)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-2.5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500"
            >
              <option value="all">Все точки</option>
              {points.filter(p => filterCity === 'all' || p.city === filterCity).map(p => (
                <option key={`point-${p.id}-${p.city}`} value={p.id}>{p.name}</option>
              ))}
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-bold text-stone-400 uppercase ml-1">Сотрудник</label>
            <select 
              value={filterWorker}
              onChange={(e) => setFilterWorker(e.target.value)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-2.5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500"
            >
              <option value="all">Все сотрудники</option>
              {workers.filter(w => filterCity === 'all' || w.city === filterCity).map(w => (
                <option key={`worker-${w.id}-${w.city}`} value={w.id}>{w.name}</option>
              ))}
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-bold text-stone-400 uppercase ml-1">Период</label>
            <select 
              value={timeRange}
              onChange={(e) => setTimeRange(e.target.value as TimeRange)}
              className="w-full bg-stone-50 border-none rounded-xl px-4 py-2.5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500"
            >
              <option value="day">День</option>
              <option value="week">Неделя</option>
              <option value="month">Месяц</option>
              <option value="quarter">Квартал</option>
              <option value="year">Год</option>
              <option value="custom">Произвольный</option>
            </select>
          </div>
        </div>

        {(timeRange === 'custom' || dateStart || dateEnd) && (
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-stone-400 uppercase ml-1">От</label>
              <input 
                type="date"
                value={dateStart}
                onChange={(e) => setDateStart(e.target.value)}
                className="w-full bg-stone-50 border-none rounded-xl px-4 py-2.5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-stone-400 uppercase ml-1">До</label>
              <input 
                type="date"
                value={dateEnd}
                onChange={(e) => setDateEnd(e.target.value)}
                className="w-full bg-stone-50 border-none rounded-xl px-4 py-2.5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500"
              />
            </div>
          </div>
        )}
      </div>

      {/* Content based on active view */}
      <AnimatePresence mode="wait">
        <motion.div
          key={activeView}
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -10 }}
          transition={{ duration: 0.2 }}
        >
          {activeView === 'overview' && renderOverview()}
          {activeView === 'salary' && renderSalary()}
          {activeView === 'comparison' && renderComparison()}
        </motion.div>
      </AnimatePresence>
    </div>
  );
}
