import React, { useState, useEffect } from 'react';
import { City } from '../App';
import { api } from '../api';
import { Plus, Trash2, AlertCircle, Megaphone, X } from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';

interface InfoPageProps {
  city: City;
  isAdmin: boolean;
}

export default function InfoPage({ city, isAdmin }: InfoPageProps) {
  const [news, setNews] = useState<any[]>([]);
  const [isAdding, setIsAdding] = useState(false);
  const [newContent, setNewContent] = useState('');
  const [isImportant, setIsImportant] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    refreshNews();
  }, [city]);

  const refreshNews = () => {
    setLoading(true);
    api.getNews(city).then(data => {
      setNews(data);
      setLoading(false);
    });
  };

  const handleAddNews = async () => {
    if (!newContent.trim()) return;
    await api.addNews({ city, content: newContent, is_important: isImportant });
    setNewContent('');
    setIsImportant(false);
    setIsAdding(false);
    refreshNews();
  };

  const handleDeleteNews = async (id: number) => {
    if (confirm('Удалить новость?')) {
      await api.deleteNews(id);
      refreshNews();
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-black tracking-tight uppercase">
          {city === 'chelyabinsk' ? 'Челябинск' : 'Озерск'}
        </h2>
        {isAdmin && (
          <button 
            onClick={() => setIsAdding(!isAdding)}
            className={`p-2 rounded-xl shadow-sm transition-all ${isAdding ? 'bg-stone-100 text-stone-500' : 'bg-emerald-600 text-white'}`}
          >
            {isAdding ? <X className="w-5 h-5" /> : <Plus className="w-5 h-5" />}
          </button>
        )}
      </div>

      <AnimatePresence>
        {isAdding && (
          <motion.div 
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className="bg-white rounded-3xl p-6 border border-stone-200 shadow-lg space-y-4"
          >
            <h3 className="font-bold text-lg flex items-center gap-2"><Megaphone className="w-5 h-5 text-emerald-600" /> Новая новость</h3>
            <textarea 
              value={newContent}
              onChange={(e) => setNewContent(e.target.value)}
              className="w-full min-h-[120px] bg-stone-50 border-none rounded-2xl p-4 focus:ring-2 focus:ring-emerald-500 outline-none font-medium text-stone-700"
              placeholder="Введите текст новости..."
            />
            <div className="flex items-center gap-3">
              <label className="flex items-center gap-3 cursor-pointer group">
                <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${isImportant ? 'bg-red-600 border-red-600' : 'border-stone-200 bg-white'}`}>
                  {isImportant && <div className="w-2 h-2 bg-white rounded-full" />}
                </div>
                <input 
                  type="checkbox" 
                  checked={isImportant} 
                  onChange={(e) => setIsImportant(e.target.checked)}
                  className="hidden"
                />
                <span className={`font-bold text-sm uppercase tracking-wider ${isImportant ? 'text-red-600' : 'text-stone-400'}`}>Важное</span>
              </label>
            </div>
            <div className="flex gap-2 pt-2">
              <button 
                onClick={handleAddNews}
                className="flex-1 bg-emerald-600 text-white font-bold py-4 rounded-2xl shadow-lg shadow-emerald-600/20 active:scale-[0.98] transition-transform"
              >
                Опубликовать
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <div className="space-y-4">
        {loading ? (
          <div className="flex justify-center p-12">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-emerald-600"></div>
          </div>
        ) : news.map((item) => (
          <motion.div 
            key={item.id}
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            className={`bg-white rounded-3xl shadow-sm border p-6 relative overflow-hidden transition-all ${item.is_important ? 'border-red-200 bg-red-50/30 ring-1 ring-red-100' : 'border-stone-200'}`}
          >
            <div className={`absolute top-0 left-0 w-1.5 h-full ${item.is_important ? 'bg-red-600' : 'bg-emerald-600'}`} />
            
            <div className="flex justify-between items-start mb-3">
              <div className="flex items-center gap-2">
                {item.is_important && <AlertCircle className="w-4 h-4 text-red-600" />}
                <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest">
                  {new Date(item.created_at).toLocaleString('ru-RU', { day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>
              {isAdmin && (
                <button onClick={() => handleDeleteNews(item.id)} className="text-stone-300 hover:text-red-500 transition-colors p-1">
                  <Trash2 className="w-4 h-4" />
                </button>
              )}
            </div>
            
            <p className={`whitespace-pre-wrap font-medium leading-relaxed ${item.is_important ? 'text-red-900' : 'text-stone-700'}`}>
              {item.content}
            </p>
          </motion.div>
        ))}
        {!loading && news.length === 0 && (
          <div className="text-center py-16 bg-stone-50 rounded-3xl border border-dashed border-stone-200">
            <Megaphone className="w-12 h-12 text-stone-200 mx-auto mb-4" />
            <p className="text-stone-400 font-bold uppercase text-xs tracking-widest">Новостей пока нет</p>
          </div>
        )}
      </div>
    </div>
  );
}
