import React, { useState, useEffect } from 'react';
import { api } from '../api';
import { Check, X, Edit2, Trash2, Filter, Clock, CheckCircle2, Search, Calendar, User, MapPin, DollarSign, ShoppingCart, ChevronRight, AlertCircle } from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';

interface ModerationPageProps {
  isAdmin: boolean;
}

export default function ModerationPage({ isAdmin }: ModerationPageProps) {
  const [reports, setReports] = useState<any[]>([]);
  const [filter, setFilter] = useState<'all' | 'pending' | 'confirmed'>('pending');
  const [editingReport, setEditingReport] = useState<any>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortBy, setSortBy] = useState<'date' | 'worker' | 'cash'>('date');
  const [expandedReport, setExpandedReport] = useState<number | null>(null);
  const [workerConflicts, setWorkerConflicts] = useState<Record<string, any>>({});

  useEffect(() => {
    if (isAdmin) {
      api.getReports().then(async (reportsData) => {
        setReports(reportsData);
        
        // Проверяем конфликты ID сотрудников
        const conflicts: Record<string, any> = {};
        const workerGroups = reportsData.reduce((acc: any, report: any) => {
          if (!acc[report.worker_id]) acc[report.worker_id] = [];
          acc[report.worker_id].push(report);
          return acc;
        }, {});
        
        for (const [workerId, workerReports] of Object.entries(workerGroups) as unknown as [string, any[]]) {
          const uniqueNames = new Set(workerReports.map(r => r.worker_name));
          if (uniqueNames.size > 1) {
            // Есть конфликт - один ID использовался разными людьми
            conflicts[workerId] = {
              names: Array.from(uniqueNames),
              reports: workerReports.length,
              dateRange: {
                start: Math.min(...workerReports.map(r => new Date(r.date).getTime())),
                end: Math.max(...workerReports.map(r => new Date(r.date).getTime()))
              }
            };
          }
        }
        
        setWorkerConflicts(conflicts);
      });
    }
  }, [isAdmin]);

  const handleStatusChange = async (id: number, status: string) => {
    const report = reports.find(r => r.id === id);
    await api.updateReport(id, { ...report, status });
    setReports(reports.map(r => r.id === id ? { ...r, status } : r));
  };

  const handleDelete = async (id: number) => {
    if (confirm('Удалить отчет?')) {
      await api.deleteReport(id);
      setReports(reports.filter(r => r.id !== id));
    }
  };

  const handleUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    await api.updateReport(editingReport.id, editingReport);
    setReports(reports.map(r => r.id === editingReport.id ? editingReport : r));
    setEditingReport(null);
  };

  const filteredReports = reports
    .filter(r => filter === 'all' || r.status === filter)
    .filter(r => {
      if (!searchTerm) return true;
      const search = searchTerm.toLowerCase();
      return (
        r.worker_name?.toLowerCase().includes(search) ||
        r.worker_id?.toString().includes(search) ||
        r.point_name?.toLowerCase().includes(search) ||
        r.comment?.toLowerCase().includes(search)
      );
    })
    .sort((a, b) => {
      if (sortBy === 'date') return new Date(b.date).getTime() - new Date(a.date).getTime();
      if (sortBy === 'worker') return a.worker_name?.localeCompare(b.worker_name) || 0;
      if (sortBy === 'cash') return b.cash - a.cash;
      return 0;
    });

  if (!isAdmin) return <div className="p-8 text-center font-bold text-red-500">Доступ запрещен</div>;

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4">
        <h2 className="text-2xl font-black tracking-tight uppercase">Модерация</h2>
        
        {/* Search and Filter Bar */}
        <div className="bg-white rounded-2xl p-4 border border-stone-200 shadow-sm space-y-4">
          {/* Search */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-stone-400 w-4 h-4" />
            <input
              type="text"
              placeholder="Поиск по имени, ID, точке или комментарию..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-stone-50 border-none rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none text-sm"
            />
          </div>
          
          {/* Filter and Sort Controls */}
          <div className="flex gap-2 flex-wrap">
            {/* Status Filter */}
            <div className="flex bg-stone-100 border border-stone-200 rounded-xl p-1 shadow-sm">
              <button 
                onClick={() => setFilter('pending')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
                  filter === 'pending' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-500'
                }`}
              >
                <Clock className="w-3 h-3" /> В ожидании
              </button>
              <button 
                onClick={() => setFilter('confirmed')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
                  filter === 'confirmed' ? 'bg-white text-emerald-600 shadow-sm' : 'text-stone-500'
                }`}
              >
                <CheckCircle2 className="w-3 h-3" /> Подтверждены
              </button>
              <button 
                onClick={() => setFilter('all')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
                  filter === 'all' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-500'
                }`}
              >
                <Filter className="w-3 h-3" /> Все
              </button>
            </div>
            
            {/* Sort */}
            <div className="flex bg-stone-100 border border-stone-200 rounded-xl p-1 shadow-sm">
              <button 
                onClick={() => setSortBy('date')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
                  sortBy === 'date' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-500'
                }`}
              >
                <Calendar className="w-3 h-3" /> Дата
              </button>
              <button 
                onClick={() => setSortBy('worker')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
                  sortBy === 'worker' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-500'
                }`}
              >
                <User className="w-3 h-3" /> Имя
              </button>
              <button 
                onClick={() => setSortBy('cash')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${
                  sortBy === 'cash' ? 'bg-white text-stone-900 shadow-sm' : 'text-stone-500'
                }`}
              >
                <DollarSign className="w-3 h-3" /> Касса
              </button>
            </div>
          </div>
          
          {/* Results Count */}
          <div className="text-xs text-stone-500 font-medium">
            Найдено отчетов: {filteredReports.length}
          </div>
        </div>
      </div>

      <div className="space-y-3">
        {filteredReports.map(report => (
          <motion.div 
            key={`report-${report.id}-${report.date}`} 
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-white rounded-2xl border border-stone-200 shadow-sm overflow-hidden hover:shadow-md transition-shadow"
          >
            {/* Header - Always Visible */}
            <div 
              className="p-4 flex justify-between items-start cursor-pointer"
              onClick={() => setExpandedReport(expandedReport === report.id ? null : report.id)}
            >
              <div className="flex-1">
                <div className="flex items-center gap-3">
                  <div className="bg-emerald-100 p-2 rounded-lg">
                    <User className="text-emerald-600 w-4 h-4" />
                  </div>
                  <div className="flex-1">
                    <p className="font-black text-lg leading-tight">{report.worker_name}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <span className="text-[10px] font-bold bg-stone-100 text-stone-500 px-2 py-0.5 rounded uppercase tracking-wider">
                        ID: {report.worker_id}
                      </span>
                      {workerConflicts[report.worker_id] && (
                        <span className="text-[10px] font-bold bg-red-100 text-red-600 px-2 py-0.5 rounded uppercase tracking-wider flex items-center gap-1">
                          <AlertCircle className="w-3 h-3" />
                          Конфликт ID
                        </span>
                      )}
                      <span className="text-[10px] font-bold bg-emerald-50 text-emerald-600 px-2 py-0.5 rounded uppercase tracking-wider">
                        {report.city === 'chelyabinsk' ? 'ЧБ' : 'ОЗ'}
                      </span>
                      <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase tracking-wider ${
                        report.status === 'confirmed' 
                          ? 'bg-emerald-100 text-emerald-700' 
                          : 'bg-amber-100 text-amber-700'
                      }`}>
                        {report.status === 'confirmed' ? 'Подтвержден' : 'В ожидании'}
                      </span>
                    </div>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <p className="text-xs font-bold text-stone-400">{new Date(report.date).toLocaleDateString('ru-RU')}</p>
                <ChevronRight className={`w-4 h-4 text-stone-400 transition-transform ${
                  expandedReport === report.id ? 'rotate-90' : ''
                }`} />
              </div>
            </div>

            {/* Quick Stats - Always Visible */}
            <div className="px-4 pb-3 grid grid-cols-3 gap-3">
              <div className="bg-stone-50 rounded-xl p-3 text-center">
                <Clock className="w-4 h-4 text-stone-400 mx-auto mb-1" />
                <p className="text-xs text-stone-500 font-medium">Часы</p>
                <p className="font-black text-stone-900">{report.hours}</p>
              </div>
              <div className="bg-emerald-50 rounded-xl p-3 text-center">
                <DollarSign className="w-4 h-4 text-emerald-500 mx-auto mb-1" />
                <p className="text-xs text-emerald-600 font-medium">Касса</p>
                <p className="font-black text-emerald-600">{report.cash}</p>
              </div>
              <div className="bg-red-50 rounded-xl p-3 text-center">
                <ShoppingCart className="w-4 h-4 text-red-500 mx-auto mb-1" />
                <p className="text-xs text-red-600 font-medium">Закуп</p>
                <p className="font-black text-red-500">{report.purchase || 0}</p>
              </div>
            </div>

            {/* Expanded Details */}
            <AnimatePresence>
              {expandedReport === report.id && (
                <motion.div
                  initial={{ height: 0, opacity: 0 }}
                  animate={{ height: 'auto', opacity: 1 }}
                  exit={{ height: 0, opacity: 0 }}
                  className="border-t border-stone-100"
                >
                  <div className="p-4 space-y-3">
                    <div className="flex items-center gap-2">
                      <MapPin className="w-4 h-4 text-stone-400" />
                      <p className="text-sm font-medium text-stone-600">Точка:</p>
                      <p className="font-bold text-stone-900">{report.point_name}</p>
                    </div>
                    
                    {report.comment && (
                      <div className="bg-stone-50 rounded-xl p-3">
                        <p className="text-xs text-stone-500 font-medium mb-1">Комментарий:</p>
                        <p className="text-sm text-stone-700 italic">"{report.comment}"</p>
                      </div>
                    )}

                    {workerConflicts[report.worker_id] && (
                      <div className="bg-red-50 rounded-xl p-3 border border-red-100">
                        <div className="flex items-center gap-2 mb-2">
                          <AlertCircle className="w-4 h-4 text-red-500" />
                          <p className="text-xs font-bold text-red-700">Конфликт ID сотрудника</p>
                        </div>
                        <p className="text-xs text-red-600 mb-2">
                          ID {report.worker_id} использовался разными сотрудниками:
                        </p>
                        <div className="space-y-1">
                          {workerConflicts[report.worker_id].names.map((name: string, index: number) => (
                            <div key={index} className="text-xs text-red-600 font-medium">
                              • {name}
                            </div>
                          ))}
                        </div>
                        <p className="text-xs text-red-500 mt-2">
                          Всего отчетов: {workerConflicts[report.worker_id].reports}
                        </p>
                      </div>
                    )}

                    {/* Action Buttons */}
                    <div className="flex gap-2 pt-2">
                      {report.status === 'pending' ? (
                        <button 
                          onClick={(e) => {
                            e.stopPropagation();
                            handleStatusChange(report.id, 'confirmed');
                          }}
                          className="flex-1 bg-emerald-600 text-white font-bold py-3 rounded-xl flex items-center justify-center gap-2 hover:bg-emerald-700 transition-colors"
                        >
                          <Check className="w-4 h-4" /> Подтвердить
                        </button>
                      ) : (
                        <button 
                          onClick={(e) => {
                            e.stopPropagation();
                            handleStatusChange(report.id, 'pending');
                          }}
                          className="flex-1 bg-stone-100 text-stone-600 font-bold py-3 rounded-xl flex items-center justify-center gap-2 hover:bg-stone-200 transition-colors"
                        >
                          <Clock className="w-4 h-4" /> В ожидание
                        </button>
                      )}
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          setEditingReport(report);
                        }}
                        className="p-3 bg-white border border-stone-200 text-stone-500 rounded-xl hover:bg-stone-50 transition-colors"
                      >
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button 
                        onClick={(e) => {
                          e.stopPropagation();
                          handleDelete(report.id);
                        }}
                        className="p-3 bg-white border border-stone-200 text-red-400 rounded-xl hover:bg-red-50 transition-colors"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </motion.div>
        ))}
        {filteredReports.length === 0 && (
          <div className="text-center py-12 text-stone-400 font-medium">
            {searchTerm ? 'Отчеты не найдены' : 'Отчетов пока нет'}
          </div>
        )}
      </div>

      {/* Edit Modal */}
      <AnimatePresence>
        {editingReport && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setEditingReport(null)}
              className="absolute inset-0 bg-stone-900/60 backdrop-blur-sm"
            />
            <motion.div 
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="relative bg-white w-full max-w-sm rounded-3xl shadow-2xl p-6"
            >
              <h3 className="text-xl font-bold mb-6">Редактировать отчет</h3>
              <form onSubmit={handleUpdate} className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-bold text-stone-400 uppercase mb-1">Часы</label>
                    <input 
                      type="number"
                      step="0.5"
                      value={editingReport.hours}
                      onChange={(e) => setEditingReport({...editingReport, hours: parseFloat(e.target.value)})}
                      className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 font-bold"
                    />
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-stone-400 uppercase mb-1">Касса</label>
                    <input 
                      type="number"
                      value={editingReport.cash}
                      onChange={(e) => setEditingReport({...editingReport, cash: parseFloat(e.target.value)})}
                      className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 font-bold"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-stone-400 uppercase mb-1">Закуп</label>
                  <input 
                    type="number"
                    value={editingReport.purchase}
                    onChange={(e) => setEditingReport({...editingReport, purchase: parseFloat(e.target.value)})}
                    className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 font-bold"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-stone-400 uppercase mb-1">Комментарий</label>
                  <textarea 
                    value={editingReport.comment || ''}
                    onChange={(e) => setEditingReport({...editingReport, comment: e.target.value})}
                    className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 font-medium min-h-[80px]"
                  />
                </div>
                <div className="flex gap-2 pt-2">
                  <button 
                    type="submit"
                    className="flex-1 bg-emerald-600 text-white font-bold py-3 rounded-xl shadow-lg shadow-emerald-600/20"
                  >
                    Сохранить
                  </button>
                  <button 
                    type="button"
                    onClick={() => setEditingReport(null)}
                    className="px-6 bg-stone-100 text-stone-600 font-bold py-3 rounded-xl"
                  >
                    Отмена
                  </button>
                </div>
              </form>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}
