import { api } from './api';

// Типы данных
interface CacheData {
  reports: any[];
  salaryPayments: any[];
  points: any[];
  workers: any[];
  cities: any[];
  rates: any[];
  news: any[];
  lastUpdated: {
    reports: string;
    salaryPayments: string;
    points: string;
    workers: string;
    cities: string;
    rates: string;
    news: string;
  };
}

// Ключи для localStorage
const CACHE_KEY = 'app_cache_data';
const LAST_UPDATE_KEY = 'last_manual_update';

class DataManager {
  private cache: CacheData = {
    reports: [],
    salaryPayments: [],
    points: [],
    workers: [],
    cities: [],
    rates: [],
    news: [],
    lastUpdated: {
      reports: '',
      salaryPayments: '',
      points: '',
      workers: '',
      cities: '',
      rates: '',
      news: ''
    }
  };

  constructor() {
    this.loadFromLocalStorage();
  }

  // Загрузка из localStorage
  private loadFromLocalStorage() {
    try {
      const cached = localStorage.getItem(CACHE_KEY);
      if (cached) {
        this.cache = JSON.parse(cached);
      }
    } catch (error) {
      console.error('Error loading cache from localStorage:', error);
    }
  }

  // Сохранение в localStorage
  private saveToLocalStorage() {
    try {
      localStorage.setItem(CACHE_KEY, JSON.stringify(this.cache));
    } catch (error) {
      console.error('Error saving cache to localStorage:', error);
    }
  }

  // Проверка можно ли обновлять данные (не чаще чем раз в час)
  private canUpdateManually(): boolean {
    const lastUpdate = localStorage.getItem(LAST_UPDATE_KEY);
    if (!lastUpdate) return true;
    
    const lastUpdateTime = new Date(lastUpdate).getTime();
    const now = new Date().getTime();
    const oneHour = 60 * 60 * 1000;
    
    return (now - lastUpdateTime) > oneHour;
  }

  // Обновление времени последнего ручного обновления
  private setLastManualUpdate() {
    localStorage.setItem(LAST_UPDATE_KEY, new Date().toISOString());
  }

  // Получение данных из кэша или API
  async getData(type: keyof CacheData, forceUpdate = false): Promise<any[]> {
    const now = new Date().toISOString();
    
    // Если данные устарели или принудительное обновление
    if (forceUpdate || this.isDataStale(type)) {
      try {
        let data: any[] = [];
        
        switch (type) {
          case 'reports':
            data = await api.getReports();
            break;
          case 'salaryPayments':
            data = await api.getSalaryPayments();
            break;
          case 'points':
            const chPoints = await api.getPoints('chelyabinsk');
            const ozPoints = await api.getPoints('ozersk');
            data = [...(chPoints || []), ...(ozPoints || [])];
            break;
          case 'workers':
            const chWorkers = await api.getWorkers('chelyabinsk');
            const ozWorkers = await api.getWorkers('ozersk');
            data = [...(chWorkers || []), ...(ozWorkers || [])];
            break;
          case 'cities':
            const chCity = await api.getCity('chelyabinsk');
            const ozCity = await api.getCity('ozersk');
            data = [chCity, ozCity].filter(Boolean);
            break;
          case 'rates':
            data = await api.getRates();
            break;
          case 'news':
            const chNews = await api.getNews('chelyabinsk');
            const ozNews = await api.getNews('ozersk');
            data = [...(chNews || []), ...(ozNews || [])];
            break;
        }
        
        // Обновляем кэш
        (this.cache as any)[type] = data;
        (this.cache.lastUpdated as any)[type] = now;
        this.saveToLocalStorage();
        
        return data;
      } catch (error) {
        console.error(`Error loading ${type}:`, error);
        // Возвращаем кэшированные данные если API недоступен
        return (this.cache as any)[type] || [];
      }
    }
    
    return (this.cache as any)[type] || [];
  }

  // Проверка устарели ли данные (30 минут)
  private isDataStale(type: keyof CacheData): boolean {
    const lastUpdated = this.cache.lastUpdated[type];
    if (!lastUpdated) return true;
    
    const lastUpdateTime = new Date(lastUpdated).getTime();
    const now = new Date().getTime();
    const thirtyMinutes = 30 * 60 * 1000;
    
    return (now - lastUpdateTime) > thirtyMinutes;
  }

  // Ручное обновление данных
  async manualUpdate(type?: keyof CacheData): Promise<boolean> {
    if (!this.canManualUpdate()) {
      return false;
    }

    try {
      if (type) {
        await this.getData(type, true);
      } else {
        // Обновляем все данные
        await Promise.all([
          this.getData('reports', true),
          this.getData('salaryPayments', true),
          this.getData('points', true),
          this.getData('workers', true),
          this.getData('cities', true),
          this.getData('rates', true),
          this.getData('news', true)
        ]);
      }
      
      this.setLastManualUpdate();
      return true;
    } catch (error) {
      console.error('Error during manual update:', error);
      return false;
    }
  }

  // Проверка можно ли ручное обновление
  canManualUpdate(): boolean {
    return this.canUpdateManually();
  }

  // Получение времени до следующего обновления
  getTimeUntilNextUpdate(): string {
    const lastUpdate = localStorage.getItem(LAST_UPDATE_KEY);
    if (!lastUpdate) return 'Доступно сейчас';
    
    const lastUpdateTime = new Date(lastUpdate).getTime();
    const now = new Date().getTime();
    const oneHour = 60 * 60 * 1000;
    const timeLeft = oneHour - (now - lastUpdateTime);
    
    if (timeLeft <= 0) return 'Доступно сейчас';
    
    const minutes = Math.floor(timeLeft / (60 * 1000));
    return `Через ${minutes} минут`;
  }

  // Добавление новых данных (с сохранением в кэш и API)
  async addData(type: keyof CacheData, data: any): Promise<boolean> {
    try {
      let result = false;
      
      switch (type) {
        case 'reports':
          result = await api.submitReport(data);
          break;
        case 'salaryPayments':
          result = await api.addSalaryPayment(data);
          break;
        case 'points':
          result = await api.addPoint(data);
          break;
        case 'workers':
          result = await api.addWorker(data);
          break;
        case 'rates':
          result = await api.addRate(data);
          break;
        case 'news':
          result = await api.addNews(data);
          break;
      }
      
      if (result) {
        // Обновляем кэш после успешного добавления
        await this.getData(type, true);
      }
      
      return result;
    } catch (error) {
      console.error(`Error adding ${type}:`, error);
      // Сохраняем локально для последующей синхронизации
      this.savePendingOperation(type, 'add', data);
      return false;
    }
  }

  // Обновление данных
  async updateData(type: keyof CacheData, id: string | number, data: any): Promise<boolean> {
    try {
      let result = false;
      
      switch (type) {
        case 'reports':
          result = await api.updateReport(Number(id), data);
          break;
        case 'points':
          result = await api.updatePoint(Number(id), data);
          break;
        case 'cities':
          result = await api.updateCity(id as any, data);
          break;
      }
      
      if (result) {
        // Обновляем кэш после успешного обновления
        await this.getData(type, true);
      }
      
      return result;
    } catch (error) {
      console.error(`Error updating ${type}:`, error);
      this.savePendingOperation(type, 'update', { id, data });
      return false;
    }
  }

  // Удаление данных
  async deleteData(type: keyof CacheData, id: string | number): Promise<boolean> {
    try {
      let result = false;
      
      switch (type) {
        case 'reports':
          result = await api.deleteReport(Number(id));
          break;
        case 'points':
          result = await api.deletePoint(Number(id));
          break;
        case 'workers':
          result = await api.deleteWorker(String(id));
          break;
        case 'rates':
          result = await api.deleteRate(Number(id));
          break;
        case 'news':
          result = await api.deleteNews(Number(id));
          break;
      }
      
      if (result) {
        // Обновляем кэш после успешного удаления
        await this.getData(type, true);
      }
      
      return result;
    } catch (error) {
      console.error(`Error deleting ${type}:`, error);
      this.savePendingOperation(type, 'delete', { id });
      return false;
    }
  }

  // Сохранение отложенных операций
  private savePendingOperation(type: keyof CacheData, operation: 'add' | 'update' | 'delete', data: any) {
    try {
      const pending = localStorage.getItem('pending_operations') || '[]';
      const operations = JSON.parse(pending);
      operations.push({ type, operation, data, timestamp: new Date().toISOString() });
      localStorage.setItem('pending_operations', JSON.stringify(operations));
    } catch (error) {
      console.error('Error saving pending operation:', error);
    }
  }

  // Синхронизация отложенных операций
  async syncPendingOperations(): Promise<number> {
    try {
      const pending = localStorage.getItem('pending_operations');
      if (!pending) return 0;
      
      const operations = JSON.parse(pending);
      let synced = 0;
      
      for (const op of operations) {
        try {
          let success = false;
          
          switch (op.operation) {
            case 'add':
              success = await this.addData(op.type, op.data);
              break;
            case 'update':
              success = await this.updateData(op.type, op.data.id, op.data.data);
              break;
            case 'delete':
              success = await this.deleteData(op.type, op.data.id);
              break;
          }
          
          if (success) synced++;
        } catch (error) {
          console.error('Error syncing operation:', error);
        }
      }
      
      // Удаляем успешно синхронизированные операции
      if (synced > 0) {
        localStorage.setItem('pending_operations', JSON.stringify(operations.slice(synced)));
      }
      
      return synced;
    } catch (error) {
      console.error('Error during sync:', error);
      return 0;
    }
  }

  // Получение количества отложенных операций
  getPendingOperationsCount(): number {
    try {
      const pending = localStorage.getItem('pending_operations');
      return pending ? JSON.parse(pending).length : 0;
    } catch (error) {
      return 0;
    }
  }

  // Очистка кэша
  clearCache() {
    this.cache = {
      reports: [],
      salaryPayments: [],
      points: [],
      workers: [],
      cities: [],
      rates: [],
      news: [],
      lastUpdated: {
        reports: '',
        salaryPayments: '',
        points: '',
        workers: '',
        cities: '',
        rates: '',
        news: ''
      }
    };
    this.saveToLocalStorage();
  }
}

export const dataManager = new DataManager();
