import React, { useState, useEffect } from 'react';
import { motion } from 'motion/react';
import { User, Plus, Search, RefreshCw, Clock, AlertCircle } from 'lucide-react';
import { dataManager } from '../dataManager';

interface WorkersPageProps {
  isAdmin: boolean;
}

export default function WorkersPage({ isAdmin }: WorkersPageProps) {
  const [workers, setWorkers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [updating, setUpdating] = useState(false);
  const [updateMessage, setUpdateMessage] = useState('');

  useEffect(() => {
    loadWorkers();
  }, []);

  const loadWorkers = async () => {
    try {
      setLoading(true);
      const workersData = await dataManager.getData('workers');
      setWorkers(workersData);
    } catch (error) {
      console.error('Error loading workers:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleManualUpdate = async () => {
    if (!dataManager.canManualUpdate()) {
      setUpdateMessage(`Обновление доступно ${dataManager.getTimeUntilNextUpdate()}`);
      setTimeout(() => setUpdateMessage(''), 3000);
      return;
    }

    try {
      setUpdating(true);
      const success = await dataManager.manualUpdate('workers');
      
      if (success) {
        await loadWorkers();
        setUpdateMessage('Данные успешно обновлены');
      } else {
        setUpdateMessage('Ошибка при обновлении данных');
      }
    } catch (error) {
      console.error('Error updating workers:', error);
      setUpdateMessage('Ошибка при обновлении данных');
    } finally {
      setUpdating(false);
      setTimeout(() => setUpdateMessage(''), 3000);
    }
  };

  const handleDeleteWorker = async (workerId: string) => {
    if (!confirm('Вы уверены, что хотите удалить этого сотрудника?')) return;

    try {
      const success = await dataManager.deleteData('workers', workerId);
      if (success) {
        await loadWorkers();
      }
    } catch (error) {
      console.error('Error deleting worker:', error);
    }
  };

  const filteredWorkers = workers.filter(worker => 
    worker.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    worker.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getRankBadge = (workerId: string) => {
    const workerReports = 0; // Здесь можно добавить логику подсчета отчетов
    if (workerReports >= 50) return <span className="px-2 py-1 bg-purple-100 text-purple-700 text-xs font-bold rounded-full">👑 Легенда</span>;
    if (workerReports >= 20) return <span className="px-2 py-1 bg-blue-100 text-blue-700 text-xs font-bold rounded-full">⭐ Профи</span>;
    if (workerReports >= 5) return <span className="px-2 py-1 bg-green-100 text-green-700 text-xs font-bold rounded-full">✅ Опытный</span>;
    return <span className="px-2 py-1 bg-gray-100 text-gray-700 text-xs font-bold rounded-full">🔰 Новичок</span>;
  };

  if (!isAdmin) return <div className="p-8 text-center font-bold text-red-500">Доступ запрещен</div>;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-black tracking-tight uppercase">Сотрудники</h2>
        <div className="flex items-center gap-3">
          {/* Кнопка обновления */}
          <button
            onClick={handleManualUpdate}
            disabled={updating}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold text-sm transition-all ${
              updating 
                ? 'bg-stone-100 text-stone-400 cursor-not-allowed' 
                : 'bg-emerald-600 text-white hover:bg-emerald-700 active:scale-95'
            }`}
          >
            <RefreshCw className={`w-4 h-4 ${updating ? 'animate-spin' : ''}`} />
            {updating ? 'Обновление...' : 'Обновить'}
          </button>

          {/* Кнопка добавления */}
          <button className="bg-emerald-600 text-white px-4 py-2 rounded-xl font-bold text-sm flex items-center gap-2 hover:bg-emerald-700 active:scale-95 transition-all">
            <Plus className="w-4 h-4" />
            Добавить
          </button>
        </div>
      </div>

      {/* Сообщение об обновлении */}
      {updateMessage && (
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className={`p-3 rounded-xl font-medium text-sm flex items-center gap-2 ${
            updateMessage.includes('успешно') 
              ? 'bg-emerald-100 text-emerald-700' 
              : 'bg-red-100 text-red-700'
          }`}
        >
          {updateMessage.includes('успешно') ? (
            <RefreshCw className="w-4 h-4" />
          ) : (
            <AlertCircle className="w-4 h-4" />
          )}
          {updateMessage}
        </motion.div>
      )}

      {/* Информация об обновлении */}
      <div className="bg-stone-100 rounded-xl p-3 flex items-center justify-between">
        <div className="flex items-center gap-2 text-sm text-stone-600">
          <Clock className="w-4 h-4" />
          <span>Следующее обновление: {dataManager.getTimeUntilNextUpdate()}</span>
        </div>
        {dataManager.getPendingOperationsCount() > 0 && (
          <div className="text-xs text-amber-600 font-medium">
            {dataManager.getPendingOperationsCount()} изменений ждут синхронизации
          </div>
        )}
      </div>

      {/* Search */}
      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-stone-400" />
        <input
          type="text"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          placeholder="Поиск по имени или ID..."
          className="w-full bg-white border border-stone-200 rounded-2xl pl-12 pr-4 py-4 shadow-sm focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium"
        />
      </div>

      {/* Loading */}
      {loading && (
        <div className="flex items-center justify-center py-12">
          <div className="w-8 h-8 border-2 border-emerald-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
      )}

      {/* Workers List */}
      {!loading && (
        <div className="space-y-3">
          {filteredWorkers.map(worker => (
            <div key={worker.id} className="bg-white rounded-2xl p-4 border border-stone-200 shadow-sm flex items-center justify-between group">
              <div className="flex items-center gap-4">
                <div className="bg-stone-100 p-3 rounded-xl text-stone-500">
                  <User className="w-5 h-5" />
                </div>
                <div>
                  <div className="flex items-center gap-2">
                    <p className="font-bold text-stone-900">{worker.name}</p>
                    {getRankBadge(worker.id)}
                  </div>
                  <p className="text-xs font-bold text-stone-400 uppercase tracking-widest">ID: {worker.id}</p>
                </div>
              </div>
              <button 
                onClick={() => handleDeleteWorker(worker.id)}
                className="opacity-0 group-hover:opacity-100 transition-opacity bg-red-500 text-white p-2 rounded-xl hover:bg-red-600 active:scale-95"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                </svg>
              </button>
            </div>
          ))}
          
          {filteredWorkers.length === 0 && (
            <div className="text-center py-12">
              <div className="w-16 h-16 bg-stone-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <User className="w-8 h-8 text-stone-400" />
              </div>
              <p className="text-stone-500 font-bold text-lg mb-2">Сотрудники не найдены</p>
              <p className="text-stone-400 text-sm">Попробуйте изменить параметры поиска</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
