import React, { useState } from 'react';
import { auth } from '../firebase-config';
import { signInAnonymously, signOut } from 'firebase/auth';
import { User, LogOut, Shield } from 'lucide-react';

export default function FirebaseAuth({ 
  isAdmin, 
  onLogin 
}: { 
  isAdmin: boolean; 
  onLogin: (status: boolean) => void;
}) {
  const [loading, setLoading] = useState(false);

  const handleAnonymousLogin = async () => {
    setLoading(true);
    try {
      await signInAnonymously(auth);
      onLogin(true);
    } catch (error) {
      console.error('Anonymous login failed:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    setLoading(true);
    try {
      await signOut(auth);
      onLogin(false);
    } catch (error) {
      console.error('Logout failed:', error);
    } finally {
      setLoading(false);
    }
  };

  if (isAdmin) {
    return (
      <div className="flex items-center gap-2">
        <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-100 text-emerald-700 rounded-full text-sm font-medium">
          <Shield className="w-3 h-3" />
          <span>Admin</span>
        </div>
        <button
          onClick={handleLogout}
          disabled={loading}
          className="p-2 text-stone-500 hover:text-stone-700 transition-colors bg-stone-100 rounded-full"
        >
          <LogOut className="w-4 h-4" />
        </button>
      </div>
    );
  }

  return (
    <button
      onClick={handleAnonymousLogin}
      disabled={loading}
      className="flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-xl font-medium text-sm hover:bg-emerald-700 active:scale-95 transition-all disabled:opacity-50"
    >
      {loading ? (
        <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
      ) : (
        <User className="w-4 h-4" />
      )}
      Войти
    </button>
  );
}
