import React, { useState, useEffect } from 'react';
import { api } from '../api';
import { City } from '../App';
import { 
  Plus, 
  Trash2, 
  Settings, 
  Percent, 
  Clock, 
  MapPin, 
  Link2, 
  Unlink, 
  Key,
  ChevronRight
} from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';

interface AdminSettingsProps {
  isAdmin: boolean;
  city: City;
}

export default function AdminSettings({ isAdmin, city }: AdminSettingsProps) {
  const [points, setPoints] = useState<any[]>([]);
  const [rates, setRates] = useState<any[]>([]);
  const [workers, setWorkers] = useState<any[]>([]);
  const [cityData, setCityData] = useState<any>(null);
  
  const [newPointName, setNewPointName] = useState('');
  const [newRate, setNewRate] = useState({ type: 'city', target_id: city, rate: '', percentage: '', date: '' });
  const [activeTab, setActiveTab] = useState<'points' | 'rates' | 'security'>('points');

  useEffect(() => {
    if (isAdmin) {
      refreshData();
    }
  }, [isAdmin, city]);

  useEffect(() => {
    if (newRate.type === 'city') {
      setNewRate(prev => ({ ...prev, target_id: city }));
    }
  }, [city]);

  const refreshData = () => {
    Promise.all([
      api.getPoints(city),
      api.getRates(),
      api.getWorkers(city),
      api.getCity(city)
    ]).then(([p, r, w, c]) => {
      setPoints(p);
      setRates(r);
      setWorkers(w);
      setCityData(c);
    });
  };

  const handleAddPoint = async () => {
    if (!newPointName) return;
    await api.addPoint({ name: newPointName, city });
    setNewPointName('');
    refreshData();
  };

  const handleDeletePoint = async (id: number) => {
    if (confirm('Удалить точку?')) {
      await api.deletePoint(id);
      refreshData();
    }
  };

  const handleAddRate = async () => {
    await api.addRate(newRate);
    setNewRate({ type: 'city', target_id: city, rate: '', percentage: '', date: '' });
    refreshData();
  };

  const handleDeleteRate = async (id: number) => {
    await api.deleteRate(id);
    refreshData();
  };

  const getTargetName = (rate: any) => {
    if (rate.type === 'city') return rate.target_id === 'chelyabinsk' ? 'Челябинск' : 'Озерск';
    if (rate.type === 'point') return points.find(p => p.id.toString() === rate.target_id)?.name || `Точка ID: ${rate.target_id}`;
    if (rate.type === 'worker') return workers.find(w => w.id === rate.target_id)?.name || `Сотрудник ID: ${rate.target_id}`;
    if (rate.type === 'day') return rate.date;
    return '';
  };

  const filteredRates = rates.filter(r => {
    if (r.type === 'day') return true;
    if (r.type === 'city') return r.target_id === city;
    if (r.type === 'point') {
      const point = points.find(p => p.id.toString() === r.target_id);
      return !point || point.city === city;
    }
    if (r.type === 'worker') {
      const worker = workers.find(w => w.id === r.target_id);
      return !worker || worker.city === city;
    }
    return true;
  });

  const handleUpdatePassword = async (newPassword: string) => {
    await api.updateCity(city, { ...cityData, access_password: newPassword });
    setCityData({ ...cityData, access_password: newPassword });
  };

  if (!isAdmin) return <div className="p-8 text-center font-bold text-red-500">Доступ запрещен</div>;

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-black tracking-tight uppercase">Настройки</h2>

      {/* Tabs */}
      <div className="flex bg-white border border-stone-200 rounded-2xl p-1 shadow-sm">
        <button 
          onClick={() => setActiveTab('points')}
          className={`flex-1 py-3 rounded-xl text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'points' ? 'bg-stone-900 text-white shadow-md' : 'text-stone-400'}`}
        >
          Точки
        </button>
        <button 
          onClick={() => setActiveTab('rates')}
          className={`flex-1 py-3 rounded-xl text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'rates' ? 'bg-stone-900 text-white shadow-md' : 'text-stone-400'}`}
        >
          Ставки
        </button>
        <button 
          onClick={() => setActiveTab('security')}
          className={`flex-1 py-3 rounded-xl text-xs font-bold uppercase tracking-wider transition-all ${activeTab === 'security' ? 'bg-stone-900 text-white shadow-md' : 'text-stone-400'}`}
        >
          Доступ
        </button>
      </div>

      <AnimatePresence mode="wait">
        {activeTab === 'points' && (
          <motion.div 
            key="points"
            initial={{ opacity: 0, x: 10 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -10 }}
            className="space-y-4"
          >
            <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm space-y-4">
              <h3 className="font-bold text-lg flex items-center gap-2"><Plus className="w-5 h-5 text-emerald-600" /> Добавить точку</h3>
              <div className="flex gap-2">
                <input 
                  type="text"
                  value={newPointName}
                  onChange={(e) => setNewPointName(e.target.value)}
                  className="flex-1 bg-stone-100 border-none rounded-xl px-4 py-3 font-bold"
                  placeholder="Название точки"
                />
                <button 
                  onClick={handleAddPoint}
                  className="bg-emerald-600 text-white px-6 rounded-xl font-bold"
                >
                  ОК
                </button>
              </div>
            </div>

            <div className="space-y-2">
              {points.map(point => (
                <div key={point.id} className="bg-white rounded-2xl p-4 border border-stone-200 shadow-sm space-y-3">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className="bg-stone-100 p-2 rounded-lg text-stone-500"><MapPin className="w-4 h-4" /></div>
                      <p className="font-bold">{point.name}</p>
                    </div>
                    <button onClick={() => handleDeletePoint(point.id)} className="text-stone-300 hover:text-red-500 transition-colors">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                  
                  <div className="flex items-center gap-2 pt-2 border-t border-stone-50">
                    <Link2 className="w-3 h-3 text-stone-400" />
                    <select 
                      value={point.merged_with || ''}
                      onChange={async (e) => {
                        const val = e.target.value;
                        await api.updatePoint(point.id, { 
                          ...point, 
                          is_merged: !!val, 
                          merged_with: val ? parseInt(val) : null 
                        });
                        refreshData();
                      }}
                      className="text-[10px] font-bold uppercase tracking-wider bg-stone-50 border-none rounded-lg px-2 py-1 outline-none text-stone-500"
                    >
                      <option value="">Не объединено</option>
                      {points.filter(p => p.id !== point.id).map(p => (
                        <option key={p.id} value={p.id}>Объединить с: {p.name}</option>
                      ))}
                    </select>
                  </div>
                </div>
              ))}
            </div>
          </motion.div>
        )}

        {activeTab === 'rates' && (
          <motion.div 
            key="rates"
            initial={{ opacity: 0, x: 10 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -10 }}
            className="space-y-4"
          >
            <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm space-y-4">
              <h3 className="font-bold text-lg flex items-center gap-2"><Percent className="w-5 h-5 text-blue-600" /> Настроить ставку</h3>
              
              <div className="space-y-3">
                <select 
                  value={newRate.type}
                  onChange={(e) => setNewRate({...newRate, type: e.target.value, target_id: e.target.value === 'city' ? city : ''})}
                  className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 font-bold"
                >
                  <option value="city">На весь город</option>
                  <option value="point">На точку</option>
                  <option value="worker">На сотрудника</option>
                  <option value="day">На один день</option>
                </select>

                {newRate.type === 'point' && (
                  <select 
                    value={newRate.target_id}
                    onChange={(e) => setNewRate({...newRate, target_id: e.target.value})}
                    className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 font-bold"
                  >
                    <option value="">Выберите точку</option>
                    {points.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                )}

                {newRate.type === 'worker' && (
                  <select 
                    value={newRate.target_id}
                    onChange={(e) => setNewRate({...newRate, target_id: e.target.value})}
                    className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 font-bold"
                  >
                    <option value="">Выберите сотрудника</option>
                    {workers.map(w => <option key={w.id} value={w.id}>{w.name} (ID: {w.id})</option>)}
                  </select>
                )}

                {newRate.type === 'day' && (
                  <input 
                    type="date"
                    value={newRate.date}
                    onChange={(e) => setNewRate({...newRate, date: e.target.value})}
                    className="w-full bg-stone-100 border-none rounded-xl px-4 py-3 font-bold"
                  />
                )}

                <div className="grid grid-cols-2 gap-3">
                  <div className="relative">
                    <Clock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-400" />
                    <input 
                      type="number"
                      value={newRate.rate}
                      onChange={(e) => setNewRate({...newRate, rate: e.target.value})}
                      className="w-full bg-stone-100 border-none rounded-xl pl-10 pr-4 py-3 font-bold"
                      placeholder="Ставка/час"
                    />
                  </div>
                  <div className="relative">
                    <Percent className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-400" />
                    <input 
                      type="number"
                      value={newRate.percentage}
                      onChange={(e) => setNewRate({...newRate, percentage: e.target.value})}
                      className="w-full bg-stone-100 border-none rounded-xl pl-10 pr-4 py-3 font-bold"
                      placeholder="% от кассы"
                    />
                  </div>
                </div>

                <button 
                  onClick={handleAddRate}
                  className="w-full bg-blue-600 text-white font-bold py-3 rounded-xl shadow-lg shadow-blue-600/20"
                >
                  Добавить правило
                </button>
              </div>
            </div>

            <div className="space-y-2">
              {filteredRates.map(rate => (
                <div key={rate.id} className="bg-white rounded-2xl p-4 border border-stone-200 shadow-sm flex items-center justify-between">
                  <div>
                    <p className="text-[10px] font-bold text-stone-400 uppercase tracking-wider">
                      {rate.type === 'city' ? 'Город' : rate.type === 'point' ? 'Точка' : rate.type === 'worker' ? 'Сотрудник' : 'День'}: {getTargetName(rate)}
                    </p>
                    <p className="font-bold text-stone-800">
                      {rate.rate} ₽/ч + {rate.percentage}%
                    </p>
                  </div>
                  <button onClick={() => handleDeleteRate(rate.id)} className="text-stone-300 hover:text-red-500 transition-colors">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))}
              {filteredRates.length === 0 && (
                <div className="text-center py-8 text-stone-400 text-xs font-bold uppercase tracking-widest">
                  Правил пока нет
                </div>
              )}
            </div>
          </motion.div>
        )}

        {activeTab === 'security' && (
          <motion.div 
            key="security"
            initial={{ opacity: 0, x: 10 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -10 }}
            className="space-y-4"
          >
            <div className="bg-white rounded-3xl p-6 border border-stone-200 shadow-sm space-y-4">
              <h3 className="font-bold text-lg flex items-center gap-2"><Key className="w-5 h-5 text-amber-500" /> Пароль доступа</h3>
              <p className="text-sm text-stone-500">Этот пароль сотрудники вводят при отправке отчета для города {city === 'chelyabinsk' ? 'Челябинск' : 'Озерск'}.</p>
              
              <div className="flex gap-2">
                <input 
                  type="text"
                  defaultValue={cityData?.access_password}
                  onBlur={(e) => handleUpdatePassword(e.target.value)}
                  className="flex-1 bg-stone-100 border-none rounded-xl px-4 py-3 font-bold text-center text-xl tracking-widest"
                  placeholder="1234"
                />
              </div>
              <p className="text-[10px] font-bold text-stone-400 uppercase text-center">Нажмите вне поля, чтобы сохранить</p>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}
